VALUES
  ('social-worker-moex-01041', 'social-worker', 'social-worker-moex-110-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關憂鬱的敘述，下列何者錯誤？', '["剛經歷分娩開始育兒的婦女的憂鬱症狀需要被關注", "青少年的憂鬱症狀容易覺察，因為他們的情緒起起伏伏", "憂鬱症不一定全然是自殺的先兆", "獲得憂鬱症診斷的女性比男性為多"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:06+00:00", "source_pdf_sha1": "4f79dc27d401", "answer_pdf_sha1": "893e87c04698", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01042', 'social-worker', 'social-worker-moex-110-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '依據Kalish與Reynolds（1976）在成年期（20-39歲）、中年期（40-59歲）、老年期（60歲以上） 等不同年齡層個體對死亡恐懼的研究，下列敘述何者正確？', '["老年期對死亡的恐懼最高", "中年期對死亡的恐懼最高", "成年期對死亡的恐懼最高", "三個年齡層對死亡恐懼的差異性不大"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:06+00:00", "source_pdf_sha1": "4f79dc27d401", "answer_pdf_sha1": "893e87c04698", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01043', 'social-worker', 'social-worker-moex-110-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '社會工作者對青少年未婚懷孕的處理，下列何者正確？', '["未婚懷孕青少年尚未成年，無法為自己的行為負責，因此社會工作者的處遇應以青少年父母的 意見為主", "社會工作者為決定生下孩子的未婚懷孕青少年提供相關資訊（如：育兒知識、收出養程序…等）", "墮胎可能觸及危害生命的議題，且容易引起後遺症，因此社會工作者應避免讓未婚懷孕青少年 做此選擇", "青少年因為性態度過於開放及心存僥倖才會發生未婚懷孕的事情，社會工作者應讓未婚懷孕青 少年為自己的行為後果負責"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:06+00:00", "source_pdf_sha1": "4f79dc27d401", "answer_pdf_sha1": "893e87c04698", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01044', 'social-worker', 'social-worker-moex-110-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關種族主義的敘述，下列何者正確？', '["對特定種族和族群成員的觀感和對待是比較低等的", "僅限於個人行為", "涉及行動，不是態度", "所有種族一律平等"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:06+00:00", "source_pdf_sha1": "4f79dc27d401", "answer_pdf_sha1": "893e87c04698", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01045', 'social-worker', 'social-worker-moex-110-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關馬克思（KarlMarx）的社會階級之敘述，下列何者錯誤？', '["階級是由一群與生產工具持共同關係的人們所組成", "階級是由政治地位或權力結構所形成", "由於支配階級常不公平的利用被支配階級，因而存在剝削事實", "階級間的不平等關係正是剝削的本質與階級鬥爭之根源"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:06+00:00", "source_pdf_sha1": "4f79dc27d401", "answer_pdf_sha1": "893e87c04698", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01046', 'social-worker', 'social-worker-moex-110-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '社會學者採用個人收入、教育程度與職業之指標建構量表，以作為測量人們所屬社會階層的綜合 依據。此稱為何種量表？', '["身心健康量表", "男女愛情量表", "生活風格量表", "社會經濟地位量表"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:06+00:00", "source_pdf_sha1": "4f79dc27d401", "answer_pdf_sha1": "893e87c04698", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01047', 'social-worker', 'social-worker-moex-110-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關功能論者對貧窮的看法，下列敘述何者錯誤？', '["貧窮是經濟功能異常所致，例如：快速工業化造成經濟系統崩潰", "貧窮或經濟不平等也具有維持社會運作之功能", "當貧窮不再能激勵人們努力貢獻社會時，貧窮才會成為社會問題", "只有藉由政治行動爭取當權者之支持，方能真正減少貧窮現象"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:06+00:00", "source_pdf_sha1": "4f79dc27d401", "answer_pdf_sha1": "893e87c04698", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01048', 'social-worker', 'social-worker-moex-110-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '2006年諾貝爾和平獎頒給了孟加拉經濟學家穆罕默德･尤努斯（MuhammadYunus）和他創辦的鄉 村銀行（GrameenBank）。下列敘述何者不符合鄉村銀行所推動的方式？', '["尤努斯的鄉村銀行主要是在鄉村地區倡導微型金融（Microfinance），運作方式和一般金融商品 無太大的不同", "尤努斯的鄉村銀行主要是提供金融服務給窮人，協助他們脫離貧窮", "鄉村銀行的運作方式為小額貸款", "貧窮者向鄉村銀行借貸時不需要任何的抵押品"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:06+00:00", "source_pdf_sha1": "4f79dc27d401", "answer_pdf_sha1": "893e87c04698", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01049', 'social-worker', 'social-worker-moex-110-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '關於貧窮及社會排除之敘述，下列何者正確？', '["社會排除所論述的，是動態的社會關係議題", "臺灣並沒有被社會排除的人口群", "貧窮議題的論述是穩定且不會因社會環境而有所變動", "貧窮與社會排除是相同的概念"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:06+00:00", "source_pdf_sha1": "4f79dc27d401", "answer_pdf_sha1": "893e87c04698", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01050', 'social-worker', 'social-worker-moex-110-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關人類道德發展之敘述，下列何者正確？', '["認知發展理論認為，幼兒道德學習來自對榜樣的觀察與模仿", "學習理論強調兒童關於道德問題的思維之有序發展過程", "Piaget認為，個人的道德判斷是由社會性的無律到生物性的他律與自律", "Kohlberg創立道德思維的三層次及六階段論"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:06+00:00", "source_pdf_sha1": "4f79dc27d401", "answer_pdf_sha1": "893e87c04698", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
